+/// Fold (icmp ne X, C) & (icmp ule (add X, -C), Y) --> (icmp ult (add X, -C-1), Y)
+/// When X is not C, adding -C won't have the same overflow behavior as X=C case,
+/// so (X-C) <= Y and X!=C together mean (X-C-1) < Y.
+/// Special case: C = -1 gives (icmp ne X, -1) & (icmp ule (add X, 1), Y) --> (icmp ult X, Y)
+static Value *foldICmpNeConstAndAddUle(ICmpInst *NeICmp, ICmpInst *UleICmp,
+                                       InstCombiner::BuilderTy &Builder) {
+  ICmpInst::Predicate NePred, UlePred;
+  Value *NeOp0, *NeOp1, *UleOp0, *UleOp1;
+
+  if (!match(NeICmp, m_ICmp(NePred, m_Value(NeOp0), m_Value(NeOp1))) ||
+      NePred != ICmpInst::ICMP_NE)
+    return nullptr;
+
+  if (!match(UleICmp, m_ICmp(UlePred, m_Value(UleOp0), m_Value(UleOp1))))
+    return nullptr;
+
+  // Match (icmp ne X, C)
+  Value *X = nullptr;
+  const APInt *C = nullptr;
+  if (match(NeOp0, m_APInt(C))) {
+    X = NeOp1;
+  } else if (match(NeOp1, m_APInt(C))) {
+    X = NeOp0;
+  } else {
+    return nullptr;
+  }
+
+  // Match (icmp ule (add X, -C), Y) or (icmp ule Y, (add X, -C))
+  // Also handle (icmp uge Y, (add X, -C)) which is equivalent
+  Value *Y = nullptr;
+  Value *AddOp = nullptr;
+  const APInt *AddC = nullptr;
+
+  APInt ExpectedAddC = -*C;  // We expect add constant to be -C
+
+  if (UlePred == ICmpInst::ICMP_ULE) {
+    if (match(UleOp0, m_Add(m_Specific(X), m_APInt(AddC))) && *AddC == ExpectedAddC) {
+      AddOp = UleOp0;
+      Y = UleOp1;
+    } else if (match(UleOp1, m_Add(m_Specific(X), m_APInt(AddC))) && *AddC == ExpectedAddC) {
+      // (icmp ule Y, (add X, -C)) -> this is Y <= X-C, not what we want
+      return nullptr;
+    }
+  } else if (UlePred == ICmpInst::ICMP_UGE) {
+    // (icmp uge Y, (add X, -C)) is equivalent to (icmp ule (add X, -C), Y)
+    if (match(UleOp1, m_Add(m_Specific(X), m_APInt(AddC))) && *AddC == ExpectedAddC) {
+      AddOp = UleOp1;
+      Y = UleOp0;
+    }
+  }
+
+  if (!AddOp || !Y)
+    return nullptr;
